+      if (this.cooldownTimer) {
+        clearInterval(this.cooldownTimer)
+        this.cooldownTimer = null
+      }
+      this.isLocked = false
+      this.cooldownProgress = 0
+    },
+
+    // Ghi điểm A
+    onScoreA() {
+      if (this.isLocked || this.isWinnerA || this.isWinnerB) return
+      
+      // Lưu lịch sử trước khi cộng
+      this.history.push({ a: this.scoreA, b: this.scoreB })
+      if (this.history.length > 20) this.history.shift() // Giới hạn 20 bước
+      
+      this.scoreA++
+      this.sendUpdate('score_A')
+    },
+
+    // Ghi điểm B
+    onScoreB() {
+      if (this.isLocked || this.isWinnerA || this.isWinnerB) return
+      
+      // Lưu lịch sử trước khi cộng
+      this.history.push({ a: this.scoreA, b: this.scoreB })
+      if (this.history.length > 20) this.history.shift()
+      
+      this.scoreB++
+      this.sendUpdate('score_B')
+    },
+
+    // Xử lý Undo
+    onUndo() {
+      if (this.isLocked || this.history.length === 0) {
+        if (this.history.length === 0) prompt.showToast({ message: 'No more history' })
+        return
+      }
+
+      // Lấy trạng thái cũ nhất từ stack
+      const lastState = this.history.pop()
+      this.scoreA = lastState.a
+      this.scoreB = lastState.b
+      
+      this.sendUpdate('undo')
+    },
+
+    sendUpdate(action) {
+      this.checkWinner()
+      this.startCooldown()
+
+      if (!this.connect) return
+
+      this.connect.send({
+        data: {
+          action: action,
+          scoreA: this.scoreA,
+          scoreB: this.scoreB,
+          timestamp: Date.now(),
+        },
+        fail: (data, code) => {
+          // Nếu gửi lỗi, ta có thể khôi phục lại từ history nếu cần
+          // Ở đây đơn giản là hiện lỗi
